import React from 'react';
import { NavLink } from 'react-router-dom';

const Sidebar = () => {
  const links = [
    { to: '/dashboard', label: 'Dashboard' },
    { to: '/products', label: 'Product Management' },
    { to: '/orders', label: 'Order Management' },
    { to: '/customers', label: 'Customer Management' },
    { to: '/analytics', label: 'Sales Analytics' },
    { to: '/promotions', label: 'Promotions' },
    { to: '/settings', label: 'Settings' },
  ];

  return (
    <aside className="bg-gray-950 text-white w-64 h-full shadow-md">
      <div className="p-6">
        <h2 className="text-lg font-semibold mb-6">Admin Dashboard</h2>
        <nav className="flex flex-col gap-4">
          {links.map(link => (
            <NavLink
              key={link.to}
              to={link.to}
              className={({ isActive }) =>
                `text-sm transition-colors ${isActive ? 'text-indigo-400' : 'text-gray-400 hover:text-white'}`
              }
            >
              {link.label}
            </NavLink>
          ))}
        </nav>
      </div>
    </aside>
  );
};

export default Sidebar;
